#include <iostream>

#define ROWS 3
#define COLS 3

bool areMatricesEqual(int m1[ROWS][COLS], int m2[ROWS][COLS], int r, int c) {
    bool areIdentical = true;
    for (int rIdx = 0; rIdx < r; rIdx++) {
        for (int cIdx = 0; cIdx < c; cIdx++) {
            if (m1[rIdx][cIdx] != m2[rIdx][cIdx]) {
                areIdentical = false;
            }
        }
    }
    return areIdentical;
}

void printMatrix(int mat[ROWS][COLS], int r, int c) {
    for (int i = 0; i < r; ++i) {
        for (int j = 0; j < c; ++j) {
            std::cout << mat[i][j] << (j == c - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }
}

int main() {
    int matrix1[ROWS][COLS] = {
        {10, 20, 30},
        {40, 50, 60},
        {70, 80, 90}
    };
    int matrix2[ROWS][COLS] = {
        {10, 20, 30},
        {40, 50, 60},
        {70, 80, 90}
    };
    int matrix3[ROWS][COLS] = {
        {10, 20, 30},
        {40, 55, 60},
        {70, 80, 90}
    };

    std::cout << "Test Case 1 (M1 vs M2, 3x3): " << (areMatricesEqual(matrix1, matrix2, 3, 3) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 2 (M1 vs M3, 3x3): " << (areMatricesEqual(matrix1, matrix3, 3, 3) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 3 (M1 vs M2, 1x2): " << (areMatricesEqual(matrix1, matrix2, 1, 2) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 4 (M1 vs M3, 2x2): " << (areMatricesEqual(matrix1, matrix3, 2, 2) ? "Equal" : "Not Equal") << std::endl;
    std::cout << "Test Case 5 (M1 vs M2, 0x0): " << (areMatricesEqual(matrix1, matrix2, 0, 0) ? "Equal" : "Not Equal") << std::endl;

    return 0;
}
